#include <cstdio>
#include <iostream>
#include <iomanip>
#include <cmath>
#include <limits>
#include <ctime>
#include <chrono>
#include <cuda_runtime.h>
#include <device_launch_parameters.h>

#define N 2048

#define IDX(i, j) ((i) + (j) * N)

void initialize_data(float* f) {
    for (int j = 0; j < N; ++j) {
        for (int i = 0; i < N; ++i) {
            if (i == 0 || i == N-1) {
                f[IDX(i,j)] = sinf(j * 2 * M_PI / (N - 1));
            }
            else if (j == 0 || j == N-1) {
                f[IDX(i,j)] = sinf(i * 2 * M_PI / (N - 1));
            }
            else {
                f[IDX(i,j)] = 0.0f;
            }
        }
    }
}

__global__ void compute_step(float* f, float* f_old, float* d_error, int n) {
    float local_error = 0.0f;

    int i_start = 1;
    int i_end = n - 2;
    int j_start = 1;
    int j_end = n - 2;

    for (int j = j_start + blockIdx.y * blockDim.y; j <= j_end; j += blockDim.y * blockDimCount_y()) {
        for (int i = i_start + blockIdx.x * blockDim.x; i <= i_end; i += blockDim.x * blockDimCount_x()) {
            if (i > i_end || j > j_end) continue;

            float t = 0.25f * (f_old[IDX(i-1,j)] +
                               f_old[IDX(i+1,j)] +
                               f_old[IDX(i,j-1)] +
                               f_old[IDX(i,j+1)]);
            float df = t - f_old[IDX(i, j)];
            f[IDX(i,j)] = t;
            local_error += df * df;
        }
    }

    // Simple reduction within block (assuming single thread per block for simplicity in translation logic or using atomic)
    // To match the reduction behavior exactly without complex block reduction code, we use atomicAdd
    atomicAdd(d_error, local_error);
}

__global__ void copy_inner(float* f_old, float* f, int n) {
    for (int j = 0; j < n; j++) {
        for (int i = 0; i < n; i++) {
            if (j >= 1 && j <= n-2 && i >= 1 && i <= n-2) {
                f_old[IDX(i,j)] = f[IDX(i,j)];
            }
        }
    }
}

// Helper to get number of blocks in a dimension if needed, but here we just launch with fixed grid
int main() {
    auto start_time = std::chrono::steady_clock::now();

    float* f_host = (float*)aligned_alloc(64, N * N * sizeof(float));
    float* f_old_host = (float*)aligned_alloc(64, N * N * sizeof(float));

    float error = std::numeric_limits<float>::max();
    const float tolerance = 1.e-5f;

    initialize_data(f_host);
    initialize_data(f_old_host);

    float* f_dev;
    float* f_old_dev;
    float* d_error;

    cudaMalloc(&f_dev, N * N * sizeof(float));
    cudaMalloc(&f_old_dev, N * N * sizeof(float));
    cudaMalloc(&d_error, sizeof(float));

    cudaMemcpy(f_dev, f_host, N * N * sizeof(float), cudaMemcpyHostToDevice);
    cudaMemcpy(f_old_dev, f_old_host, N * N * sizeof(float), cudaMemcpyHostToDevice);

    const int max_iters = 10000;
    int num_iters = 0;

    auto start = std::chrono::steady_clock::now();

    dim3 block(16, 16);
    dim3 grid((N-2 + block.x - 1) / block.x, (N-2 + block.y - 1) / block.y);

    while (error > tolerance && num_iters < max_iters) {
        error = 0.0f;
        cudaMemset(d_error, 0, sizeof(float));

        compute_step<<<grid, block>>>(f_dev, f_old_dev, d_error, N);

        copy_inner<<<grid, block>>>(f_old_dev, f_dev, N);

        cudaMemcpy(&error, d_error, sizeof(float), cudaMemcpyDeviceToHost);
        error = sqrtf(error / (N * N));

        if (num_iters % 1000 == 0) {
            std::cout << "Error after iteration " << num_iters << " = " << error << std::endl;
        }

        ++num_iters;
    }

    auto end = std::chrono::steady_clock::now();
    auto time = std::chrono::duration_cast<std::chrono::nanoseconds>(end - start).count();
    std::cout << "Average execution time per iteration: " << (time * 1e-9f) / num_iters << " (s)\n";

    cudaMemcpy(f_host, f_dev, N * N * sizeof(float), cudaMemcpyDeviceToHost);

    if (error <= tolerance && num_iters < max_iters) {
        std::cout << "PASS" << std::endl;
    }
    else {
        std::cout << "FAIL" << std::endl;
        cudaFree(f_dev);
        cudaFree(f_old_dev);
        cudaFree(d_error);
        free(f_host);
        free(f_old_host);
        return -1;
    }

    cudaFree(f_dev);
    cudaFree(f_old_dev);
    cudaFree(d_error);
    free(f_host);
    free(f_old_host);

    auto end_time = std::chrono::steady_clock::now();
    auto total_time = std::chrono::duration_cast<std::chrono::nanoseconds>(end_time - start_time).count();
    double duration = total_time * 1e-9;
    std::cout << "Total elapsed time: " << std::setprecision(4) << duration << " seconds" << std::endl;

    return 0;
}
